const fs = require('fs');
const path = require('path');

const migrationsDir = path.resolve('packages/database/postgres');
const outputFile = path.resolve('packages/database/supabase/servicepro-bootstrap.sql');

function migrationFiles() {
  return fs.readdirSync(migrationsDir).filter(name => /^\d{3}_.+\.sql$/.test(name)).sort();
}

function buildBootstrapSql() {
  const files = migrationFiles();
  const sections = [
    '-- ServicePro Supabase bootstrap bundle.',
    '-- Generated by npm run supabase:bundle. Do not edit this file directly.',
    '-- Run this bundle once on a blank project. Use npm run supabase:provision for tracked, resumable setup.',
    '',
    'CREATE TABLE IF NOT EXISTS postgres_runtime_migrations (',
    '  version text PRIMARY KEY,',
    '  applied_at timestamptz NOT NULL DEFAULT now()',
    ');'
  ];

  for (const file of files) {
    const sql = fs.readFileSync(path.join(migrationsDir, file), 'utf8').trim();
    const version = file.replaceAll("'", "''");
    sections.push(
      '',
      `-- BEGIN SERVICEPRO MIGRATION ${file}`,
      'BEGIN;',
      sql,
      `INSERT INTO postgres_runtime_migrations (version) VALUES ('${version}') ON CONFLICT (version) DO NOTHING;`,
      'COMMIT;',
      `-- END SERVICEPRO MIGRATION ${file}`
    );
  }

  return `${sections.join('\n')}\n`;
}

function writeBootstrapSql() {
  fs.mkdirSync(path.dirname(outputFile), { recursive: true });
  fs.writeFileSync(outputFile, buildBootstrapSql());
  return { outputFile, migrations: migrationFiles().length };
}

if (require.main === module) {
  const result = writeBootstrapSql();
  console.log(`Wrote ${result.migrations} migrations to ${path.relative(process.cwd(), result.outputFile)}.`);
}

module.exports = { buildBootstrapSql, migrationFiles, outputFile, writeBootstrapSql };
